// src/components/MoldEdit.js

import React, {useState, useEffect} from 'react';
import {supabase} from '../supabaseClient';
import {useNavigate, useParams} from 'react-router-dom';
import {
    TextField,
    Button,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    Typography,
    Box,
} from '@mui/material';
import { useTranslation } from 'react-i18next';

function MoldEdit() {
    const {id} = useParams();
    const [moldId, setMoldId] = useState('');
    const [status, setStatus] = useState('');
    const [inspectionStatus, setInspectionStatus] = useState('');
    const [inspector, setInspector] = useState('');
    const [moldCount, setMoldCount] = useState(0);
    const navigate = useNavigate();
    const { t, i18n } = useTranslation();

    useEffect(() => {
        async function fetchMold() {
            const {data, error} = await supabase.from('molds').select('*').eq('id', id).single();
            if (error) {
                console.error(t('Failed to fetch mold data:'), error);
            } else {
                setMoldId(data.mold_id);
                setStatus(data.status);
                setInspectionStatus(data.inspection_status);
                setInspector(data.inspector);
                setMoldCount(data.mold_count);
            }
        }

        fetchMold();
    }, [id, t]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        const {error} = await supabase
            .from('molds')
            .update({
                mold_id: moldId,
                status: status,
                inspection_status: inspectionStatus,
                inspector: inspector,
                mold_count: moldCount,
            })
            .eq('id', id);
        if (error) {
            console.error(t('Failed to edit mold:'), error);
        } else {
            navigate('/mold-list');
        }
    };

    const toggleLanguage = () => {
        i18n.changeLanguage(i18n.language === 'ko' ? 'en' : 'ko');
    };

    return (
        <Box sx={{maxWidth: 600, margin: '0 auto', mt: 4, p: 2}}>
            <Box sx={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2}}>
                <Typography variant="h5">{t('Mold Edit')}</Typography>
                <Button variant="outlined" onClick={toggleLanguage}>
                    {i18n.language === 'ko' ? 'English' : '한국어'}
                </Button>
            </Box>
            <form onSubmit={handleSubmit}>
                <TextField
                    label={t('Mold ID')}
                    value={moldId}
                    onChange={(e) => setMoldId(e.target.value)}
                    fullWidth
                    margin="normal"
                />
                <FormControl fullWidth margin="normal">
                    <InputLabel id="status-label">{t('Status')}</InputLabel>
                    <Select
                        labelId="status-label"
                        id="status"
                        value={status}
                        onChange={(e) => setStatus(e.target.value)}
                        label={t('Status')}
                    >
                        <MenuItem value="Received">{t('Received')}</MenuItem>
                        <MenuItem value="Shipped">{t('Shipped')}</MenuItem>
                        {/* 필요한 상태 옵션 추가 */}
                    </Select>
                </FormControl>
                <FormControl fullWidth margin="normal">
                    <InputLabel id="inspectionStatus-label">{t('Inspection Status')}</InputLabel>
                    <Select
                        labelId="inspectionStatus-label"
                        id="inspectionStatus"
                        value={inspectionStatus}
                        onChange={(e) => setInspectionStatus(e.target.value)}
                        label={t('Inspection Status')}
                    >
                        <MenuItem value="PASS">{t('PASS')}</MenuItem>
                        <MenuItem value="WAITING">{t('WAITING')}</MenuItem>
                        <MenuItem value="FAIL">{t('FAIL')}</MenuItem>
                        {/* 필요한 Inspection Status 옵션 추가 */}
                    </Select>
                </FormControl>
                <TextField
                    label={t('Inspector')}
                    value={inspector}
                    onChange={(e) => setInspector(e.target.value)}
                    fullWidth
                    margin="normal"
                />
                <TextField
                    label={t('Mold Count')}
                    type="number"
                    value={moldCount}
                    onChange={(e) => setMoldCount(e.target.value)}
                    fullWidth
                    margin="normal"
                />
                <Button type="submit" variant="contained" color="primary" sx={{mt: 2}}>
                    {t('Edit')}
                </Button>
            </form>
        </Box>
    );
}

export default MoldEdit;
